SELECT

FROM M_STOCK


        AND STOCK_CODE = #{stockCode}


        AND STOCK_NAME LIKE CONCAT('%', #{stockName}, '%')


        AND TYPE_CODE = #{typeCode}


        AND MARKET = #{market}


        AND DEL_FLG = #{delFlg}


ORDER BY

        STOCK_CODE
        ID


        ASC
        DESC

LIMIT #{limit} OFFSET #{offset}

SELECT
    COUNT(1)
FROM M_STOCK


        AND STOCK_CODE = #{stockCode}


        AND STOCK_NAME LIKE CONCAT('%', #{stockName}, '%')


        AND TYPE_CODE = #{typeCode}


        AND MARKET = #{market}


        AND DEL_FLG = #{delFlg}

SELECT ID, STOCK_CODE, STOCK_NAME, MARKET FROM M_STOCK
DEL_FLG = '0'
AND ( STOCK_CODE LIKE CONCAT('%', #{keyword}, '%') OR STOCK_NAME LIKE CONCAT('%', #{keyword}, '%') )
AND MARKET = #{market}
ORDER BY STOCK_CODE ASC LIMIT #{limit}

SELECT RP.STOCK_CODE, MS.STOCK_NAME, RP.START_DATE, RP.END_DATE, RP.START_CLOSE_PRICE, RP.END_CLOSE_PRICE, (RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) AS CHANGE_AMOUNT, ROUND((RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) * 100 / RP.START_CLOSE_PRICE, 2) AS CHANGE_PERCENT FROM ( SELECT P.STOCK_CODE, P.START_DATE, P.END_DATE, START_HISTORY.CLOSE_PRICE AS START_CLOSE_PRICE, END_HISTORY.CLOSE_PRICE AS END_CLOSE_PRICE FROM ( SELECT STOCK_CODE, MIN(TRANS_DATE) AS START_DATE, MAX(TRANS_DATE) AS END_DATE FROM M_STOCK_PRICE_HISTORY WHERE TRANS_DATE BETWEEN #{startDate} AND #{endDate} GROUP BY STOCK_CODE HAVING MIN(TRANS_DATE) < MAX(TRANS_DATE) ) P JOIN M_STOCK_PRICE_HISTORY START_HISTORY ON START_HISTORY.STOCK_CODE = P.STOCK_CODE AND START_HISTORY.TRANS_DATE = P.START_DATE JOIN M_STOCK_PRICE_HISTORY END_HISTORY ON END_HISTORY.STOCK_CODE = P.STOCK_CODE AND END_HISTORY.TRANS_DATE = P.END_DATE WHERE START_HISTORY.CLOSE_PRICE IS NOT NULL AND START_HISTORY.CLOSE_PRICE <> 0 AND END_HISTORY.CLOSE_PRICE IS NOT NULL ) RP LEFT JOIN M_STOCK MS ON RP.STOCK_CODE = MS.STOCK_CODE
ROUND((RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) * 100 / RP.START_CLOSE_PRICE, 2) >= #{threshold}
ROUND((RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) * 100 / RP.START_CLOSE_PRICE, 2) <= -#{threshold}
ORDER BY
CHANGE_PERCENT DESC CHANGE_PERCENT ASC , RP.STOCK_CODE ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM ( SELECT RP.STOCK_CODE FROM ( SELECT P.STOCK_CODE, START_HISTORY.CLOSE_PRICE AS START_CLOSE_PRICE, END_HISTORY.CLOSE_PRICE AS END_CLOSE_PRICE FROM ( SELECT STOCK_CODE, MIN(TRANS_DATE) AS START_DATE, MAX(TRANS_DATE) AS END_DATE FROM M_STOCK_PRICE_HISTORY WHERE TRANS_DATE BETWEEN #{startDate} AND #{endDate} GROUP BY STOCK_CODE HAVING MIN(TRANS_DATE) < MAX(TRANS_DATE) ) P JOIN M_STOCK_PRICE_HISTORY START_HISTORY ON START_HISTORY.STOCK_CODE = P.STOCK_CODE AND START_HISTORY.TRANS_DATE = P.START_DATE JOIN M_STOCK_PRICE_HISTORY END_HISTORY ON END_HISTORY.STOCK_CODE = P.STOCK_CODE AND END_HISTORY.TRANS_DATE = P.END_DATE WHERE START_HISTORY.CLOSE_PRICE IS NOT NULL AND START_HISTORY.CLOSE_PRICE <> 0 AND END_HISTORY.CLOSE_PRICE IS NOT NULL ) RP
ROUND((RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) * 100 / RP.START_CLOSE_PRICE, 2) >= #{threshold}
ROUND((RP.END_CLOSE_PRICE - RP.START_CLOSE_PRICE) * 100 / RP.START_CLOSE_PRICE, 2) <= -#{threshold}
) C

